import{_ as a,c as t,o as e,a4 as r}from"./chunks/framework.HaEZziQ1.js";const b=JSON.parse('{"title":"ECMAScript语法简介-文档-资源","description":"","frontmatter":{},"headers":[],"relativePath":"Document/JavaScript笔记/ECMAScript语法/ECMAScript语法简介-文档-资源.md","filePath":"Document/JavaScript笔记/ECMAScript语法/ECMAScript语法简介-文档-资源.md","lastUpdated":1709668918000}'),i={name:"Document/JavaScript笔记/ECMAScript语法/ECMAScript语法简介-文档-资源.md"},l=r('<h1 id="ecmascript语法简介-文档-资源" tabindex="-1">ECMAScript语法简介-文档-资源 <a class="header-anchor" href="#ecmascript语法简介-文档-资源" aria-label="Permalink to &quot;ECMAScript语法简介-文档-资源&quot;">​</a></h1><h2 id="ecmascript语法简介" tabindex="-1">ECMAScript语法简介 <a class="header-anchor" href="#ecmascript语法简介" aria-label="Permalink to &quot;ECMAScript语法简介&quot;">​</a></h2><p>ECMA（European Computer Manufacturers Association）中文名称为欧洲计算机制造商协会，这个组织的目标是评估、开发和认可电信和计算机标准。1994 年后该组织改名为 Ecma 国际。</p><h3 id="_1-什么是-ecmascript" tabindex="-1">1.什么是 ECMAScript <a class="header-anchor" href="#_1-什么是-ecmascript" aria-label="Permalink to &quot;1.什么是 ECMAScript&quot;">​</a></h3><ul><li>ECMAScript 是由 Ecma 国际通过 ECMA-262 标准化的脚本程序设计语言。</li></ul><h3 id="_2-什么是-ecma-262" tabindex="-1">2.什么是 ECMA-262 <a class="header-anchor" href="#_2-什么是-ecma-262" aria-label="Permalink to &quot;2.什么是 ECMA-262&quot;">​</a></h3><p>Ecma 国际制定了许多标准，而 ECMA-262 只是其中的一个，所有标准列表查看</p><ul><li><a href="http://www.ecma-international.org/publications/standards/Standard.htm" target="_blank" rel="noreferrer">http://www.ecma-international.org/publications/standards/Standard.htm</a></li></ul><h3 id="_3-ecma-262-历史" tabindex="-1">3.ECMA-262 历史 <a class="header-anchor" href="#_3-ecma-262-历史" aria-label="Permalink to &quot;3.ECMA-262 历史&quot;">​</a></h3><h4 id="ecma-262-ecmascript-历史版本查看网址" tabindex="-1">ECMA-262（ECMAScript）历史版本查看网址 <a class="header-anchor" href="#ecma-262-ecmascript-历史版本查看网址" aria-label="Permalink to &quot;ECMA-262（ECMAScript）历史版本查看网址&quot;">​</a></h4><ul><li><a href="http://www.ecma-international.org/publications/standards/Ecma-262-arch.htm" target="_blank" rel="noreferrer">http://www.ecma-international.org/publications/standards/Ecma-262-arch.htm</a></li></ul><h4 id="ecmasript-语法提案库" tabindex="-1">ECMASript 语法提案库 <a class="header-anchor" href="#ecmasript-语法提案库" aria-label="Permalink to &quot;ECMASript 语法提案库&quot;">​</a></h4><ul><li><a href="https://github.com/ungap" target="_blank" rel="noreferrer">https://github.com/ungap</a></li></ul><h4 id="ecmasript-标准文档" tabindex="-1">ECMASript 标准文档 <a class="header-anchor" href="#ecmasript-标准文档" aria-label="Permalink to &quot;ECMASript 标准文档&quot;">​</a></h4><ul><li><a href="https://tc39.es/ecma262/" target="_blank" rel="noreferrer">https://tc39.es/ecma262/</a></li></ul><p>注：从 ES6 开始，每年的6月份发布一个版本，版本号比年份最后一位大 1</p><h3 id="_4-谁在维护-ecma-262" tabindex="-1">4.谁在维护 ECMA-262 <a class="header-anchor" href="#_4-谁在维护-ecma-262" aria-label="Permalink to &quot;4.谁在维护 ECMA-262&quot;">​</a></h3><p>TC39（Technical Committee 39）是推进 ECMAScript 发展的委员会。其会员都是公司（其中主要是浏览器厂商，有苹果、谷歌、微软、因特尔等）。TC39 定期召开会议，会议由会员公司的代表与特邀专家出席</p><h4 id="标准组织tc39" tabindex="-1">标准组织TC39 <a class="header-anchor" href="#标准组织tc39" aria-label="Permalink to &quot;标准组织TC39&quot;">​</a></h4><ul><li>Ecma TC39组织库：<a href="https://github.com/tc39" target="_blank" rel="noreferrer">https://github.com/tc39</a></li><li>ECMAScript提案：<a href="https://github.com/tc39/proposals" target="_blank" rel="noreferrer">https://github.com/tc39/proposals</a></li></ul><h3 id="_5-为什么要学习-es6" tabindex="-1">5.为什么要学习 ES6 <a class="header-anchor" href="#_5-为什么要学习-es6" aria-label="Permalink to &quot;5.为什么要学习 ES6&quot;">​</a></h3><ul><li><p>⚫ ES6 的版本变动内容最多，具有里程碑意义</p></li><li><p>⚫ ES6 加入许多新的语法特性，编程实现更简单、高效</p></li><li><p>⚫ ES6 是前端发展趋势，就业必备技能</p></li></ul><h3 id="_6-es6-级其他es版本兼容性" tabindex="-1">6.ES6 级其他ES版本兼容性 <a class="header-anchor" href="#_6-es6-级其他es版本兼容性" aria-label="Permalink to &quot;6.ES6 级其他ES版本兼容性&quot;">​</a></h3><p>查看兼容性</p><ul><li><p>各大浏览器对 ES 语法的支持：<a href="http://kangax.github.io/compat-table/es6/" target="_blank" rel="noreferrer">http://kangax.github.io/compat-table/es6/</a></p></li><li><p><a href="http://kangax.github.io/compat-table/" target="_blank" rel="noreferrer">http://kangax.github.io/compat-table/</a></p></li></ul><p>语法兼容性查询网站<code>can i use</code>：<a href="https://caniuse.com" target="_blank" rel="noreferrer">https://caniuse.com</a></p><p>ES6+版本的代码 --&gt; 通过 webpack的Babel插件 --&gt; ES5 版本支持的代码</p><ul><li>兼容性更好</li></ul><h2 id="书籍文档相关" tabindex="-1">书籍文档相关 <a class="header-anchor" href="#书籍文档相关" aria-label="Permalink to &quot;书籍文档相关&quot;">​</a></h2><p>推荐阮一峰的《ES6标准入门》：<a href="https://es6.ruanyifeng.com/" target="_blank" rel="noreferrer">https://es6.ruanyifeng.com/</a></p><p>《JavaScript高级教程（第4版）》[红宝石书]</p><p>《JavaScript权威指南》[犀牛书]</p><h2 id="资源" tabindex="-1">资源 <a class="header-anchor" href="#资源" aria-label="Permalink to &quot;资源&quot;">​</a></h2><p>ECMA-262，ECMAScript的语法标准（语法草案和版本相关）：<a href="https://www.ecma-international.org/publications-and-standards/standards/ecma-262/" target="_blank" rel="noreferrer">https://www.ecma-international.org/publications-and-standards/standards/ecma-262/</a></p><h2 id="mdn语法查询" tabindex="-1">MDN语法查询 <a class="header-anchor" href="#mdn语法查询" aria-label="Permalink to &quot;MDN语法查询&quot;">​</a></h2><p><a href="https://developer.mozilla.org/zh-CN/" target="_blank" rel="noreferrer">https://developer.mozilla.org/zh-CN/</a></p>',36),c=[l];function o(n,h,p,s,d,m){return e(),t("div",null,c)}const _=a(i,[["render",o]]);export{b as __pageData,_ as default};
